import { type PropsWithChildren, type ReactNode, useCallback } from 'react';
import { isElement } from 'react-is';

import { CONTENT_OFFSET_Y, VALUE_MARKER_WIDTH } from './constants.js';
import { ValueMarkerPointerPosition } from './types.js';
import { calculateCenteredIcon } from './utils/calculate-centered-icon.js';
import { calculateCenteredText } from './utils/calculate-centered-text.js';
import { getMarkerGeometry } from './utils/get-marker-geometry.js';
import { useCanvas } from '../../../../../canvas/hooks/useCanvas.js';
import {
  MARKER_BORDER_RADIUS,
  MARKER_OPACITY,
  MARKER_STROKE_WIDTH,
} from '../../../../constants.js';
import { useAnnotationsIconImages } from '../../../../hooks/useAnnotationsIconImages.js';
import { CANVAS_PIXEL_OFFSET } from '../../constants.js';
import { applyMarkerStyles } from '../../utils/apply-marker-styles.js';
import { renderIconContent } from '../../utils/render-icon-to-canvas.js';
import { renderTextContent } from '../../utils/render-text-in-canvas.js';

const EXTENDED_AND_COLORED_EMOJI_REGEX =
  /(\p{Emoji}\uFE0F|\p{Emoji_Presentation})/gu;

const isEmojiSymbol = (text: ReactNode) =>
  typeof text === 'string' &&
  text.match(EXTENDED_AND_COLORED_EMOJI_REGEX)?.length === 1;

// In retina display emojis are a little bit smaller.
const EMOJI_RETINA_OFFSET = 1.5;

export type ValueMarkerRendererProps = {
  x: number;
  y: number;
  width: number;
  height: number;
  fillColor: string;
  strokeColor: string;
  opacity?: number;
  brightness?: string;
  orientation?: ValueMarkerPointerPosition;
};

function renderStringToContext(
  ctx: CanvasRenderingContext2D,
  children: string,
  x: number,
  width: number,
  orientation: ValueMarkerPointerPosition,
  y: number,
  fillColor: string,
) {
  const contentWidth = ctx.measureText(children).width;
  const xOffset = calculateCenteredText(x, width, orientation, contentWidth);
  const contentOffset = y + CONTENT_OFFSET_Y;
  renderTextContent(
    ctx,
    children,
    xOffset,
    contentOffset,
    orientation,
    fillColor,
  );
}

export const ValueMarkerRenderer = (
  props: PropsWithChildren<ValueMarkerRendererProps>,
) => {
  const {
    x,
    y,
    fillColor,
    strokeColor,
    children,
    opacity = MARKER_OPACITY,
    brightness,
    width: widthProp,
    orientation = 'center',
  } = props;

  const width = Math.max(widthProp, VALUE_MARKER_WIDTH);
  const geometry = getMarkerGeometry(
    orientation,
    x,
    y - MARKER_STROKE_WIDTH,
    isEmojiSymbol(children) ? VALUE_MARKER_WIDTH : width,
  );

  const iconImages = useAnnotationsIconImages();

  const draw = useCallback(
    (ctx: CanvasRenderingContext2D) => {
      ctx.beginPath();
      // Web-kit browsers need to move to the initial point to avoid weird behavior: APPDEV-8494
      ctx.moveTo(geometry[0].x, geometry[0].y);
      for (let i = 0; i < geometry.length; i += 2) {
        const vertex = geometry[i];
        const lineBisect = geometry[i + 1];

        ctx.arcTo(
          vertex.x - CANVAS_PIXEL_OFFSET,
          vertex.y - CANVAS_PIXEL_OFFSET,
          lineBisect.x - CANVAS_PIXEL_OFFSET,
          lineBisect.y - CANVAS_PIXEL_OFFSET,
          MARKER_BORDER_RADIUS,
        );
      }
      applyMarkerStyles(ctx, opacity, brightness, fillColor, strokeColor);
      ctx.closePath();

      if (isElement(children)) {
        const iconX = calculateCenteredIcon(x, orientation);

        renderIconContent(ctx, children, iconImages, iconX, y);
      } else if (
        typeof children === 'string' &&
        EXTENDED_AND_COLORED_EMOJI_REGEX.test(children)
      ) {
        // this makes no sense, but if I remove this assertion, a weird behavior is shown in retina.
        EXTENDED_AND_COLORED_EMOJI_REGEX.test(children);
        const retinaOffset = devicePixelRatio > 1 ? EMOJI_RETINA_OFFSET : 0;
        renderStringToContext(
          ctx,
          children,
          x + retinaOffset,
          isEmojiSymbol(children) ? VALUE_MARKER_WIDTH : width,
          orientation,
          y,
          fillColor,
        );
      } else {
        renderStringToContext(
          ctx,
          children as string,
          x,
          width,
          orientation,
          y,
          fillColor,
        );
      }

      return false;
    },
    [
      geometry,
      opacity,
      fillColor,
      children,
      iconImages,
      x,
      y,
      brightness,
      width,
    ],
  );

  useCanvas('annotations-value-marker', draw);

  return null;
};
